def trimmed_mean(nums):
    if not nums or len(nums) < 3:
        return None

    nums.sort()
    median = nums[len(nums) // 2]
    left_cutoff = [n for n in nums if n > median][1]
    right_cutoff = [n for n in nums if n < median][-2]
    return sum([n for n in nums if n not in {left_cutoff, right_cutoff}]) / (len(nums) - 2)
